class Solution:
    def minimumCost(self, nums: List[int]) -> int:
        n = len(nums)
        # We need to split into 3 contiguous subarrays, so we need to choose 2 split points
        # The first subarray must start at index 0, so the first split point is between i and i+1
        # The second split point is between j and j+1, where j > i
        min_cost = float('inf')
        for i in range(1, n - 1):
            for j in range(i + 1, n):
                cost = nums[0] + nums[i] + nums[j]
                if cost < min_cost:
                    min_cost = cost
        return min_cost
